    /**
     * Calculates the maximum depth of a binary tree rooted at the given node.
     * Handles null input by returning a depth of zero.
     * 
     * @param root The root node of the binary tree.
     * @return The maximum depth of the tree as an integer.
     */
    public static int calculateTreeDepth(TreeNode root) {
        if (root == null) {
            return 0;
        }
