#include <algorithm>
#include <vector>
#include <string>

std::string normalizeURL(std::string url) {
    size_t protocolPos = url.find("://");
    std::string protocol, rest;
    if (protocolPos != std::string::npos) {
        protocol = url.substr(0, protocolPos);
        std::transform(protocol.begin(), protocol.end(), protocol.begin(), ::tolower);
        rest = url.substr(protocolPos + 3);
    } else {
        protocol = "http";
        rest = url;
    }

    size_t queryPos = rest.find('?');
    std::string base = rest.substr(0, queryPos);
    std::string query = (queryPos != std::string::npos) ? rest.substr(queryPos + 1) : "";

    if (!query.empty()) {
        std::vector<std::pair<std::string, std::string>> params;
        size_t start = 0;
        while (true) {
            size_t end = query.find('&', start);
            std::string param = (end == std::string::npos) ? query.substr(start) : query.substr(start, end - start);
            size_t eqPos = param.find('=');
            std::string key = param.substr(0, eqPos);
            std::string value = (eqPos == std::string::npos) ? "" : param.substr(eqPos + 1);
            params.emplace_back(key, value);
            if (end == std::string::npos) break;
            start = end + 1;
        }

        std::sort(params.begin(), params.end(), [](const auto& a, const auto& b) { return a.first < b.first; });

        std::string sortedQuery;
        for (size_t i = 0; i < params.size(); ++i) {
            if (i != 0) sortedQuery += "&";
            sortedQuery += params[i].first;
            if (!params[i].second.empty()) sortedQuery += "=" + params[i].second;
        }
        query = sortedQuery;
    }

    std::string normalized = protocol + "://" + base;
    if (!query.empty()) normalized += "?" + query;
    return normalized;
}
