use std::collections::{HashSet, VecDeque};

struct Edge {
    from: i32,
    to: i32,
    weight: i32,
}

struct Graph {
    edges: Vec<Edge>,
}

fn graph_edge_prune(graph: &mut Graph) -> &mut Graph {
    let threshold_weight = 10;
    let mut edges_to_remove: Vec<Edge> = Vec::new();

    // Collect edges below threshold
    for edge in &graph.edges {
        if edge.weight < threshold_weight {
            edges_to_remove.push(Edge { from: edge.from, to: edge.to, weight: edge.weight });
        }
    }

    // Attempt to remove each edge and check connectivity
    for edge in edges_to_remove {
        let index = graph.edges.iter().position(|e| e.from == edge.from && e.to == edge.to && e.weight == edge.weight);
        if let Some(i) = index {
            let removed_edge = graph.edges.remove(i);
            if !is_connected(graph) {
                graph.edges.push(removed_edge);
            }
        }
    }

    graph
}

fn is_connected(graph: &Graph) -> bool {
    let mut vertices = HashSet::new();
    for edge in &graph.edges {
        vertices.insert(edge.from);
        vertices.insert(edge.to);
    }
    if vertices.is_empty() {
        return true;
    }
    let start = *vertices.iter().next().unwrap();
    let mut visited = HashSet::new();
    let mut queue = VecDeque::new();
    visited.insert(start);
    queue.push_back(start);

    while let Some(v) = queue.pop_front() {
        for edge in &graph.edges {
            if edge.from == v && !visited.contains(&edge.to) {
                visited.insert(edge.to);
                queue.push_back(edge.to);
            }
            if edge.to == v && !visited.contains(&edge.from) {
                visited.insert(edge.from);
                queue.push_back(edge.from);
            }
        }
    }

    visited.len() == vertices.len()
}
