def checkGraphConnectivity(graph):
    if not isinstance(graph, list):
        return False
    n = len(graph)
    if n < 3 or n > 20:
        return False
    for row in graph:
        if not isinstance(row, list) or len(row) != n:
            return False
        for val in row:
            if not isinstance(val, int) or val not in (0, 1):
                return False
    for start in range(n):
        visited = set()
        queue = [start]
        visited.add(start)
        while queue:
            current = queue.pop(0)
            for neighbor, connected in enumerate(graph[current]):
                if connected and neighbor not in visited:
                    visited.add(neighbor)
                    queue.append(neighbor)
        if len(visited) != n:
            return False
    return True
